CREATE TABLE products (
  product_id  INT PRIMARY KEY,
  name        VARCHAR(80),
  price       DECIMAL(8,2),
  stock       INT,
  category    VARCHAR(40),
  discount    DECIMAL(4,1) DEFAULT 0.0
);

INSERT INTO products VALUES
  (1, 'Laptop',       999.99, 50, 'Electronics', 0),
  (2, 'Mouse',         19.99,200, 'Electronics', 0),
  (3, 'Keyboard',      59.99,120, 'Electronics', 0),
  (4, 'Desk',         250.00, 30, 'Furniture',   0),
  (5, 'Office Chair', 175.00, 15, 'Furniture',   0),
  (6, 'Notebook',       5.99,500, 'Stationery',  0);

-- Update 1: Change price of one product
UPDATE products SET price = 1099.99 WHERE product_id = 1;

-- Update 2: Apply 10% discount to all Electronics
UPDATE products SET discount = 10.0 WHERE category = 'Electronics';

-- Update 3: Decrease stock by 5 for Laptop (simulate sale)
UPDATE products SET stock = stock - 5 WHERE product_id = 1;

-- Update 4: Recalculate effective price column (computed update)
ALTER TABLE products ADD COLUMN sale_price DECIMAL(8,2);
UPDATE products SET sale_price = ROUND(price * (1 - discount / 100), 2);

SELECT name, price, discount, stock, sale_price
FROM products
ORDER BY category, name;

CREATE TABLE orders (
  order_id  INT PRIMARY KEY,
  customer  VARCHAR(50),
  status    VARCHAR(20),
  total     DECIMAL(8,2)
);

INSERT INTO orders VALUES
  (1, 'Alice', 'pending',    150.00),
  (2, 'Bob',   'processing', 200.00),
  (3, 'Carol', 'pending',     80.00),
  (4, 'Dave',  'shipped',   350.00),
  (5, 'Eve',   'pending',    120.00);

-- SAFE PRACTICE 1: SELECT first to verify affected rows before updating
SELECT order_id, customer, status FROM orders WHERE status = 'pending';

-- If result is correct, run the UPDATE
UPDATE orders SET status = 'processing' WHERE status = 'pending';

-- Verify the update
SELECT * FROM orders ORDER BY order_id;

-- SAFE PRACTICE 2: Wrap in a transaction so you can review and rollback
BEGIN;
  UPDATE orders SET total = total * 1.1 WHERE customer = 'Dave';  -- 10% price increase
  SELECT * FROM orders WHERE customer = 'Dave';  -- review the change
ROLLBACK;  -- undo — decide not to apply

-- Verify Dave's total is unchanged after rollback
SELECT order_id, customer, total FROM orders WHERE customer = 'Dave';
